+                using GDNFwdHKernel = Catlass::Gemm::Kernel::GDNFwdHKernel<half, half, half, workspaceType>;
+                GDNFwdHKernel gdnFwdH;
+                gdnFwdH.Init(k, w, u, g, inital_state, cu_seqlens, chunk_indices, h, v_new, final_state, tiling, user);
+                gdnFwdH.Process();
+            }
+        }
+    }
